#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int arg0,
    __global const int* d_gpuWall,
    __global const int* d_gpuResult_src,
    __global int* d_gpuResult_dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    int min_val;
    int current_val;

    current_val = d_gpuResult_src[gid];
    min_val = current_val;

    if (gid > 0) {
        int left = d_gpuResult_src[gid - 1];
        if (left < min_val) min_val = left;
    }

    if (gid < cols - 1) {
        int right = d_gpuResult_src[gid + 1];
        if (right < min_val) min_val = right;
    }

    d_gpuResult_dst[gid] = d_gpuWall[t * cols + gid] + min_val;
}
